{
    nCorrectors     2;
    nNonOrthogonalCorrectors 0;
    nOuterCorrectors 2;
    nInnerCorrectors 0;
    pRefCell        0;
    pRefValue       0;
    mergeTolerance  1e-04;
    maxCo           10;
}
```

